const block = document.querySelector('.block-global-settings');

    /* ── Standard reveals (badge, heading, desc, bottom, cta) ── */
    const reveals = block.querySelectorAll('.gs-reveal, .gs-reveal-badge, .gs-reveal-cta');
    const revealIO = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          e.target.classList.add('visible');
          revealIO.unobserve(e.target);
        }
      });
    }, { threshold: 0.15 });
    reveals.forEach(el => revealIO.observe(el));

    /* ── Card build-up sequence ── */
    function buildCard(card, baseDelay = 0) {
      // Collect all build steps for this card
      const isStack = card.classList.contains('build-stack');
      const rows = card.querySelectorAll('.build-row, .build-font-row');
      const steps = [
        { el: card,                                cls: 'built', delay: baseDelay },
        { el: card.querySelector('.build-header'), cls: 'built', delay: baseDelay + 250 },
        { el: card.querySelector('.build-divider'),cls: 'built', delay: baseDelay + 450 },
        ...Array.from(rows).map((el, i) => ({
          el, cls: 'built', delay: baseDelay + 650 + i * 150
        })),
        { el: card.querySelector('.build-more'),   cls: 'built', delay: baseDelay + 650 + rows.length * 150 + 100 },
      ];

      steps.forEach(({ el, cls, delay }) => {
        if (el) setTimeout(() => el.classList.add(cls), delay);
      });

      // Return the total duration so next card can chain
      const last = steps[steps.length - 1];
      return last ? last.delay + 200 : baseDelay;
    }

    /* Trigger card builds when cards area scrolls into view */
    const cardsArea = block.querySelector('.block-global-settings__cards');
    const cardIO = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          cardIO.unobserve(e.target);
          const area = e.target;

          // All cards overlap — each starts 200ms after previous frame appears
          const stagger = 400;
          const card1 = area.querySelector('[data-card="colors"]');
          const card2 = area.querySelector('[data-card="fonts"]');
          const card3 = area.querySelector('[data-card="elements"]');

          if (card1) buildCard(card1, 0);
          if (card2) buildCard(card2, stagger);
          if (card3) buildCard(card3, stagger * 2);
        }
      });
    }, { threshold: 0.2 });
    cardIO.observe(cardsArea);
